import{_ as a,o as t,c as o,ag as d}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Modern: reemplazos Unix basados en Rust | Dotfiles (ES)","titleTemplate":":title","description":"Alias modernos para eza, bat y ripgrep. Sustituye utilidades Unix heredadas por alternativas Rust más rápidas.","frontmatter":{"title":"Alias Modern: reemplazos Unix basados en Rust","description":"Alias modernos para eza, bat y ripgrep. Sustituye utilidades Unix heredadas por alternativas Rust más rápidas.","lang":"es-ES","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Modern: reemplazos Unix basados en Rust preview","canonical":"/es/aliases/modern/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Modern: reemplazos Unix basados en Rust","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Modern | Dotfiles","permalink":"/es/aliases/modern/","sidebar":true,"meta":[{"name":"keywords","content":"alias modern, eza, bat, ripgrep, herramientas cli rust, dotfiles, shell"}]},"headers":[],"relativePath":"es/aliases/modern/index.md","filePath":"es/aliases/modern/index.md","lastUpdated":1773010926000}'),s={name:"es/aliases/modern/index.md"};function r(i,e,n,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="alias-modern" tabindex="-1">Alias Modern <a class="header-anchor" href="#alias-modern" aria-label="Permalink to &quot;Alias Modern&quot;">​</a></h1><p>Reemplazos más rápidos e inteligentes para comandos Unix heredados.</p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Los alias modern definidos en <code>modern.aliases.sh</code> proporcionan alternativas Rust a las herramientas Unix tradicionales. Estos alias se cargan automáticamente por <code>chezmoi</code> y vuelven a los comandos estándar si las herramientas modernas no están disponibles.</p><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><h3 id="listado-de-archivos-con-eza" tabindex="-1">Listado de archivos con eza <a class="header-anchor" href="#listado-de-archivos-con-eza" aria-label="Permalink to &quot;Listado de archivos con eza&quot;">​</a></h3><p>Reemplaza <code>ls</code> cuando <code>eza</code> está instalado.</p><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ls</code></td><td><code>eza --icons</code></td><td>Listar archivos con iconos</td></tr><tr><td><code>ll</code></td><td><code>eza -alF</code></td><td>Formato de lista larga</td></tr><tr><td><code>la</code></td><td><code>eza -a</code></td><td>Listar todos los archivos, incluidos ocultos</td></tr><tr><td><code>lt</code></td><td><code>eza --tree</code></td><td>Mostrar árbol de directorios</td></tr></tbody></table><p>Vuelve a <code>ls</code> si <code>eza</code> no está instalado.</p><h3 id="contenido-de-archivos-con-bat" tabindex="-1">Contenido de archivos con bat <a class="header-anchor" href="#contenido-de-archivos-con-bat" aria-label="Permalink to &quot;Contenido de archivos con bat&quot;">​</a></h3><p>Reemplaza <code>cat</code> cuando <code>bat</code> está instalado.</p><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>cat</code></td><td><code>bat</code></td><td>Mostrar contenido con resaltado de sintaxis</td></tr></tbody></table><h3 id="busqueda-con-ripgrep" tabindex="-1">Búsqueda con ripgrep <a class="header-anchor" href="#busqueda-con-ripgrep" aria-label="Permalink to &quot;Búsqueda con ripgrep&quot;">​</a></h3><p>Reemplaza <code>grep</code> cuando <code>rg</code> está instalado.</p><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>grep</code></td><td><code>rg</code></td><td>Buscar contenido con Ripgrep</td></tr></tbody></table>',15)])])}const u=a(s,[["render",r]]);export{m as __pageData,u as default};
